const esc = (value) => String(value)
  .replaceAll("&", "&amp;")
  .replaceAll("<", "&lt;")
  .replaceAll(">", "&gt;")
  .replaceAll('"', "&quot;")
  .replaceAll("'", "&#039;");

const stateClass = (value) => {
  const state = String(value).toLowerCase();
  if (state.includes("active") || state.includes("listening") || state.includes("achieved") || state.includes("succeeded")) return "is-positive";
  if (state.includes("executing")) return "is-running";
  if (state.includes("blocked")) return "is-blocked";
  if (state.includes("draft") || state.includes("superseded")) return "is-muted";
  if (state.includes("unavailable") || state === "—") return "is-unknown";
  return "";
};

const workflowRows = (corpus, mode = "ledger") => corpus.workflows.map((workflow, index) => {
  const selected = index === 0;
  if (mode === "ledger") {
    return `
      <article class="workflow-row ${selected ? "is-selected" : ""}">
        <div class="workflow-number">0${index + 1}</div>
        <div class="workflow-main">
          <div class="workflow-titleline">
            <h3>${esc(workflow.name)}</h3>
            <span class="state ${stateClass(workflow.lifecycle)}">${esc(workflow.lifecycle)}</span>
          </div>
          <p>${esc(workflow.trigger)}</p>
          <div class="mini-topology" aria-label="Configured topology">
            ${workflow.topology.map((node, nodeIndex) => `<span>${esc(node)}</span>${nodeIndex < workflow.topology.length - 1 ? "<i aria-hidden=\"true\"></i>" : ""}`).join("")}
          </div>
        </div>
        <dl class="workflow-facts">
          <div><dt>Active runs</dt><dd>${workflow.active ? esc(workflow.active) : "No active run"}</dd></div>
          <div><dt>Execution</dt><dd class="${stateClass(workflow.latestExecution)}">${esc(workflow.latestExecution)}</dd></div>
          <div><dt>Domain</dt><dd class="${stateClass(workflow.latestDomain)}">${esc(workflow.latestDomain)}</dd></div>
          <div><dt>Verification</dt><dd class="${stateClass(workflow.verification)}">${esc(workflow.verification)}</dd></div>
          <div><dt>Cost</dt><dd class="${stateClass(workflow.cost)}">${esc(workflow.cost)}</dd></div>
        </dl>
      </article>`;
  }
  return `
    <article class="workflow-strip ${selected ? "is-selected" : ""}">
      <div class="strip-index">W-0${index + 1}</div>
      <div class="strip-name"><strong>${esc(workflow.name)}</strong><span>${esc(workflow.lifecycle)}</span></div>
      <div class="strip-trigger"><span>Trigger</span>${esc(workflow.trigger)}</div>
      <div class="strip-chain">${workflow.topology.map((node) => `<span>${esc(node)}</span>`).join("")}</div>
      <div class="strip-run"><span>Live</span>${workflow.active ? `${esc(workflow.active)} active` : "No active run"}</div>
      <div class="strip-end">${esc(workflow.latestExecution)} / ${esc(workflow.latestDomain)}</div>
    </article>`;
}).join("");

const runTable = (corpus) => `
  <div class="data-table" role="table" aria-label="Run history">
    <div class="data-row data-head" role="row">
      <span>Workflow</span><span>Reference</span><span>Execution</span><span>Domain result</span><span>Verification</span><span>Cost</span>
    </div>
    ${corpus.recentRuns.map((run) => `
      <div class="data-row" role="row">
        <strong>${esc(run.workflow)}</strong>
        <span>${esc(run.ref)}</span>
        <span class="${stateClass(run.execution)}">${esc(run.execution)}</span>
        <span class="${stateClass(run.domain)}">${esc(run.domain)}</span>
        <span class="${stateClass(run.verification)}">${esc(run.verification)}</span>
        <span class="${stateClass(run.cost)}">${esc(run.cost)}</span>
      </div>`).join("")}
  </div>`;

const agentRows = (corpus) => corpus.agents.map((agent) => `
  <article class="agent-row">
    <div class="agent-identity"><span class="agent-mark" aria-hidden="true">${esc(agent.name.slice(0, 2).toUpperCase())}</span><strong>${esc(agent.name)}</strong></div>
    <span class="state ${agent.availability === "In use" ? "is-positive" : "is-muted"}">${esc(agent.availability)}</span>
    <div><small>Model</small>${esc(agent.model)}</div>
    <div><small>Harness</small>${esc(agent.harness)}</div>
    <div><small>Authority ceiling</small>${esc(agent.ceiling)}</div>
    <div><small>Workflows</small>${esc(agent.workflows)}</div>
    <div><small>Live</small>${agent.active ? `${esc(agent.active)} executing` : "No active run"}</div>
  </article>`).join("");

const spendTruth = (corpus) => corpus.spend.truth.map((item) => `
  <article class="truth-row ${stateClass(item.label)}">
    <strong>${esc(item.label)}</strong>
    <span>${esc(item.value)}</span>
    <small>${esc(item.state)}</small>
  </article>`).join("");

const createSteps = (corpus) => corpus.creation.steps.map((step, index) => `
  <li class="${index === 0 ? "is-current" : ""}"><span>${String(index + 1).padStart(2, "0")}</span>${esc(step)}</li>`).join("");

